const client = $input.first().json;
const req    = $('Webhook · CAPI trigger').first().json.body || {};

// Guard: CAPI must be enabled (skip for test events)
if (!req.test_event && (client.capi_enabled || 'No') !== 'Yes') return [];

const pixelId    = client.capi_pixel_id || '';
const capiToken  = client.capi_token    || '';
if (!pixelId || !capiToken) return [];

// Determine event name from request or rules
let eventName = req.event_name || 'Lead';
const stage   = (req.stage || '').toLowerCase();
const score   = parseInt(req.nba_score) || 0;
const threshold = parseInt(client.capi_score_threshold) || 50;

if (!req.event_name) {
  const BOOKED = ['consultation_booked','appt_booked','visit_booked','converted','booked'];
  const BAD    = ['not_interested','opt_out','lost'];
  if (BOOKED.some(s => stage.includes(s)))     eventName = client.capi_rule_conv || 'Purchase';
  else if (BAD.some(s => stage.includes(s)))   eventName = client.capi_rule_bad  || 'off';
  else if (score >= threshold)                 eventName = client.capi_rule_qual || 'Lead';
  else if (req.is_new_lead)                    eventName = client.capi_rule_new  || 'off';
  else                                         eventName = 'off';
}

if (eventName === 'off' || eventName === 'negative') return [];

// SHA-256 hash helper (Web Crypto via n8n global crypto)
async function sha256(str) {
  if (!str) return '';
  const clean = str.trim().toLowerCase();
  const buf   = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(clean));
  return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,'0')).join('');
}

const phone = (req.phone || '').replace(/[^0-9]/g, '');
const name  = (req.name  || '').trim().toLowerCase();

const hashedPhone = phone ? await sha256(phone) : '';
const nameParts   = name.split(' ');
const fn = nameParts[0]  ? await sha256(nameParts[0]) : '';
const ln = nameParts[1]  ? await sha256(nameParts[nameParts.length-1]) : '';

const eventId = `lv-${req.lead_id || req.client_id}-${Date.now()}`;

const userData = {};
if (hashedPhone) userData.ph   = [hashedPhone];
if (fn)          userData.fn   = [fn];
if (ln)          userData.ln   = [ln];
if (req.external_id || req.lead_id) userData.external_id = [String(req.lead_id || req.external_id)];

const payload = {
  data: [{
    event_name: eventName,
    event_time: Math.floor(Date.now() / 1000),
    event_id:   eventId,
    action_source: 'other',
    user_data: userData,
    custom_data: {
      lead_stage: req.stage || '',
      nba_score:  req.nba_score || 0,
      client_id:  String(req.client_id || ''),
    }
  }]
};

if (req.test_event) payload.test_event_code = 'TEST12345';

return [{ json: { pixelId, capiToken, payload, eventName, clientId: String(req.client_id), statKey: req.test_event ? null : eventName } }];

const prep   = $('Code · Prep CAPI event').first().json;
const result = $input.first().json;
if (!prep.statKey) return [];
const success = !result.error && (result.events_received || result.fbtrace_id);
const client  = $('HTTP · Get client').first().json;
const total   = parseInt(client.capi_stat_total || 0) + 1;
const fail    = parseInt(client.capi_stat_fail  || 0) + (success ? 0 : 1);
let   good    = parseInt(client.capi_stat_good  || 0);
let   conv    = parseInt(client.capi_stat_conv  || 0);
if (success) {
  if (prep.eventName === 'Purchase' || prep.eventName === 'CompleteRegistration') conv++;
  else good++;
}
return [{ json: { clientId: prep.clientId, total, good, conv, fail, now: new Date().toISOString() } }];
